INSERT INTO `business_center_content` (`id`, `section_key`, `title`, `body`, `is_active`, `updated_by`, `updated_at`) VALUES
('1', 'hero', 'Production and Business Operation Services', 'Sales, inventory, cash flow, rentals, fishpond operations, proposal requests, logbook entries, and official reports in one record management system.', '1', '1', '2026-05-14 04:36:54'),
('2', 'mission_vision', 'Mission and Vision', 'Vision: The Mindoro State University is a center of excellence in agriculture and fishery, science, technology, culture and education of globally competitive lifelong learners in a diverse yet cohesive society.\n\nMission: The University commits to produce 21st-century skilled lifelong learners and generates and commercializes innovative technologies by providing excellent and relevant services in instruction, research, extension, and production through industry-driven curricula, collaboration, internationalization, and continual organizational growth for sustainable development.', '1', '1', '2026-05-14 04:36:54'),
('3', 'services', 'Campus Services', 'Daily operation tools for the campus business center and income-generating projects.', '1', '1', '2026-05-14 04:36:54'),
('4', 'features', 'What the System Helps Manage', 'Sales records and POS transactions\nCash in, cash out, and net cash monitoring\nInventory catalog, low stock alerts, and stock ledger\nFishpond monitoring, harvest income, and expense records\nStall rentals, toga releases, payments, and overdue records\nProposal requests and administrative approval workflow\nOffice logbook entries for visits and service requests\nPrintable official reports for campus operations', '1', '1', '2026-05-14 04:36:54'),
('5', 'contact', 'Visit the Mindoro State University  Business Center', 'Mindoro State University Bongabong Campus Production and Business Operation Office.', '1', '1', '2026-05-20 19:33:54'),
('6', 'footer', 'Production and Business Operation Record Management System', 'Official campus operations records for sales, inventory, cash flow, projects, rentals, proposals, logbook, reports, and audit monitoring.', '1', '1', '2026-05-14 04:36:54');
